function kubo(hi: number, nano: number) {
  let s: string = ""
  for (let a: number = 0; a < hi; a++) {
    for (let e: number = 0; e < nano; e++) {
      if (a % 3 == 0) {
        s = "ME" + s
      } else if (a % 3 == 1) {
        s = "LA" + s
      } else {
        s = "UN" + s
      }
    }
    s = "\n" + s // quebra a linha
  }
  return s
}
